        "Variants/ios-uikit/App/RootViewController.swift": #"""
import UIKit

final class RootViewController: UIViewController {
    private let greeting = UILabel()

    override func viewDidLoad() {
        super.viewDidLoad()

        view.backgroundColor = .systemBackground

        greeting.text = "{{PROJECT_NAME}}"
        greeting.font = .preferredFont(forTextStyle: .largeTitle)
        greeting.adjustsFontForContentSizeCategory = true
        greeting.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(greeting)

        NSLayoutConstraint.activate([
            greeting.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            greeting.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
    }
}

"""#,
        "Variants/ios-uikit/App/SceneDelegate.swift": #"""
import UIKit

final class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    var window: UIWindow?

    func scene(
        _ scene: UIScene,
        willConnectTo session: UISceneSession,
        options connectionOptions: UIScene.ConnectionOptions
    ) {
        guard let windowScene = scene as? UIWindowScene else { return }

        // Built in code rather than from a storyboard: storyboards produce the
        // same unreadable merge conflicts that this project uses XcodeGen to
        // avoid in the project file.
        let window = UIWindow(windowScene: windowScene)
        window.rootViewController = RootViewController()
        window.makeKeyAndVisible()
        self.window = window
    }
}

